const PACKED =
  figma.root.getSharedPluginData('keymate', 'colorPackA') +
  '|' +
  figma.root.getSharedPluginData('keymate', 'colorPackB')

const cols = await figma.variables.getLocalVariableCollectionsAsync()
for (const c of cols) {
  if (c.name === 'Keymate / Raw / Color' || c.name === 'Keymate / Primitive / Color') {
    c.remove()
  }
}

const rawCol = figma.variables.createVariableCollection('Keymate / Raw / Color')
rawCol.renameMode(rawCol.modes[0].modeId, 'Value')
const rawMode = rawCol.modes[0].modeId
const rawIds = {}

for (const part of PACKED.split('|')) {
  const til = part.indexOf('~')
  const nm = part.slice(0, til)
  const rest = part.slice(til + 1)
  const [rs, gs, bs, as] = rest.split(',')
  const col = { r: Number(rs), g: Number(gs), b: Number(bs), a: Number(as) }
  const varName = 'raw/' + nm
  const v = figma.variables.createVariable(varName, rawCol, 'COLOR')
  v.scopes = []
  v.setValueForMode(rawMode, col)
  v.setVariableCodeSyntax('WEB', 'var(--' + varName.replace(/[\s\/%,]+/g, '-') + ')')
  rawIds[varName] = v.id
}

const primCol = figma.variables.createVariableCollection('Keymate / Primitive / Color')
primCol.renameMode(primCol.modes[0].modeId, 'Value')
const primMode = primCol.modes[0].modeId

for (const part of PACKED.split('|')) {
  const til = part.indexOf('~')
  const nm = part.slice(0, til)
  const varName = 'raw/' + nm
  const rid = rawIds[varName]
  const pv = figma.variables.createVariable(nm, primCol, 'COLOR')
  pv.scopes = nm.includes('contrast-text')
    ? ['TEXT_FILL']
    : ['FRAME_FILL', 'SHAPE_FILL', 'TEXT_FILL', 'STROKE_COLOR']
  pv.setValueForMode(primMode, { type: 'VARIABLE_ALIAS', id: rid })
  pv.setVariableCodeSyntax('WEB', 'var(--' + nm.replace(/[\s\/%,]+/g, '-') + ')')
}

figma.root.setSharedPluginData('keymate', 'colorPackA', '')
figma.root.setSharedPluginData('keymate', 'colorPackB', '')

return {
  rawCount: Object.keys(rawIds).length,
  primitiveCount: PACKED.split('|').length,
}
